import{_ as a,o as r,c as t,ae as n}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Link Debugger","description":"","frontmatter":{"title":"Link Debugger","slug":"link-debugger-deprecated"},"headers":[],"relativePath":"marketer-hub/link-debugger-deprecated.md","filePath":"marketer-hub/link-debugger-deprecated.md"}'),i={name:"marketer-hub/link-debugger-deprecated.md"};function o(s,e,l,h,u,c){return r(),t("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Link Debugger allows you to see detailed information about your Branch Link. You will be able to see the click behavior of your Branch Link through and see all of the key/value pairs behind the link to help with any troubleshooting you might have with Branch Links.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to access the Link Debugger, you need <strong>VIEW</strong> access on the <a href="./add-manage-users-roles-permissions-access.html"><strong>Link-Level Settings</strong> Permissions</a> on your Branch Dashboard account.</p><h2 id="accessing-link-debugger" tabindex="-1">Accessing Link Debugger <a class="header-anchor" href="#accessing-link-debugger" aria-label="Permalink to &quot;Accessing Link Debugger&quot;">​</a></h2><p>There are a couple of different ways to access the Link Debugger on a given Branch Link.</p><h3 id="short-links" tabindex="-1">Short Links <a class="header-anchor" href="#short-links" aria-label="Permalink to &quot;Short Links&quot;">​</a></h3><p>Link Debugger can be accessed on Short Links through the <a href="https://dashboard.branch.io/quick-links/manager" target="_blank" rel="noreferrer">Branch Dashboard&#39;s Short Links Manager</a>. Here you will find your Short Links, and with each Short Link you can access the Link Debugger using the <strong>Debug</strong> option</p><h3 id="url-parameter" tabindex="-1">URL Parameter <a class="header-anchor" href="#url-parameter" aria-label="Permalink to &quot;URL Parameter&quot;">​</a></h3><p>You can also access the Link Debugger on <em>any</em> existing Branch Link by adding the <code>debug=1</code> query parameter on your Branch Link. For example:</p><ul><li>Branch Link: <code>https://branch.app.link/link123</code></li><li>Link Debugger for Branch Link: <code>https://branch.app.link/link123?debug=1</code></li></ul><h2 id="link-routing-debugger" tabindex="-1">Link Routing Debugger <a class="header-anchor" href="#link-routing-debugger" aria-label="Permalink to &quot;Link Routing Debugger&quot;">​</a></h2><p>A useful troubleshooting feature is the <strong>Link Routing Debugger</strong> section. The tool allows you to better understand how your link will route users across different browsers and operating systems.</p><p>In this section, you can get the step-by-step behavior of your Branch Link by selecting an OS and click location. From there, the Link Routing Debugger will outline the <em>click redirect outcome</em> depending on if the app is installed at the time of click or not.</p><h2 id="link-details" tabindex="-1">Link Details <a class="header-anchor" href="#link-details" aria-label="Permalink to &quot;Link Details&quot;">​</a></h2><p>You can also get granular information about your Branch Link by viewing the <strong>Link Details</strong> section.</p><p>With the Link Details section, you have the ability to view all of the respective key/value pairs attached to your Branch Link. These keys vary from analytics tags like <em>campaign, channel, &amp; feature</em> to functional keys like <em>$deeplink_path &amp; $canonical_url</em>.</p><p>In the <em>link data</em> key, you&#39;ll also see useful tooltips next to each key that defines it. This can be useful for developers and marketing teams to determine what other data may be tied to the Branch Link.</p>',18)])])}const k=a(i,[["render",o]]);export{d as __pageData,k as default};
